      ASSERT_TRUE(res);
    }
    {
      const auto res = sqlgen::exec(conn, "SELECT 1 FROM pragma_foreign_key_list('Score') WHERE \"table\"='Course' AND \"from\"='CID' AND \"to\"='CID';");
      ASSERT_TRUE(res);
    }

