struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    // 1. Establish database connection
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        // Handle connection error - return empty vector or throw exception
        return {};
    }
    auto conn = conn_result.value();

    // 2. Create base SELECT query using sqlgen::read
    auto query = sqlgen::read<std::vector<Book>>;

    // 3. Dynamically add WHERE conditions based on filters
    auto condition = sqlgen::nothing;

    // Title keyword search (LIKE)
    if (filters.title_keyword) {
        condition = condition && sqlgen::col<"title">.like("%" + *filters.title_keyword + "%");
    }

    // Minimum year (>=)
    if (filters.min_year) {
        condition = condition && sqlgen::col<"year"> >= *filters.min_year;
    }

    // Genre (=)
    if (filters.genre) {
        condition = condition && sqlgen::col<"genre"> == *filters.genre;
    }

    // Maximum price (<=)
    if (filters.max_price) {
        condition = condition && sqlgen::col<"price"> <= *filters.max_price;
    }

    // 4. Combine conditions and execute query
    if (!condition) {
        // No valid conditions - return empty vector
        return {};
    }

    auto full_query = query | sqlgen::where(condition);
    auto result = full_query(conn);

    // 5. Return results
    if (result) {
        return result.value();
    } else {
        // Handle query execution error
        return {};
    }
}

}  // namespace query_search_books_by_criteria
