#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect(":memory:");

  // Create tables using sqlgen's fluent interface
  conn(create_table<User> | if_not_exists);
  conn(create_table<Friendship> | if_not_exists);

  // Insert data using sqlgen's fluent interface
  conn(insert(users));
  conn(insert(friendships));

  // Execute the first query: find mutual friends using SELF-JOIN
  auto mutualFriendsQuery = select_from<User, "u1">(
      "username"_t1.as<"user1_name">(),
      "username"_t4.as<"user2_name">(),
      count().as<"mutual_friends">()
  )
  | inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
  | inner_join<Friendship, "f2">("user_id2"_t2 == "user_id1"_t3)
  | inner_join<User, "u2">("user_id2"_t3 == "user_id"_t4)
  | where("user_id"_t1 < "user_id"_t4 && 
          exists(select_from<Friendship, "f3">(
              "user_id1"_t5 == "user_id"_t1 && 
              "user_id2"_t5 == "user_id"_t4
          )))
  | group_by("user_id"_t1, "user_id"_t4)
  | having(count() > 0)
  | to<std::vector<FriendConnection>>;

  // Execute the second query: find users with more than average friends
  auto popularUsersQuery = select_from<User, "u">(
      "user_id"_t1,
      "username"_t1,
      count().as<"friend_count">()
  )
  | left_join(Friendship, "f")("user_id"_t1 == "user_id1"_t2)
  | group_by("user_id"_t1, "username"_t1)
  | having(count() > avg(count()))
  | to<std::vector<std::pair<int, std::string>>>;

  // Execute the queries and return results
  auto mutualFriendsResult = mutualFriendsQuery(conn);
  auto popularUsersResult = popularUsersQuery(conn);

  // Return mutual friends results as specified in the function signature
  return mutualFriendsResult.value();
}

}  // namespace analyze_social_network
```

