  auto child_insert_result = sqlgen::write(conn, child);
  if (!child_insert_result) {
    return false;
  }

  // 4. Delete parent using sqlgen::delete_from with where condition
  auto delete_result = (sqlgen::delete_from<Parent> | sqlgen::where("parent_id"_c == 1))(conn);
